<script setup>
import Switch from "@/Components/Inputs/Switch.vue";
import Example from "@/Docs/Example.vue";
import Preview from "@/Docs/Preview.vue";
import Prop from "@/Docs/Prop.vue";
import { reactive } from "vue";
import DocPage from "@/Docs/DocPage.vue";

const state = reactive({
    toggle: true,
});
</script>

<template>
    <DocPage import="global">
        <template #title> Switch </template>
        <template #content>
            <Example title="Základní použití">
                <p><Prop>Switch</Prop> funguje jako boolean input napojený přes <Prop>v-model</Prop>. Vizuálně připomíná přepínač.</p>
                <Preview
                    code='
          <template>
            <Switch v-model="toggle" label="Zapnout funkci" />
          </template>
        '
                >
                    <Switch v-model="state.toggle" label="Zapnout funkci" />
                </Preview>
            </Example>

            <Example title="Inverzní logika">
                <p>Pomocí <Prop>inverted</Prop> můžeš obrátit chování – zaškrtnutý znamená <code>false</code>, nezaškrtnutý <code>true</code>.</p>
                <Preview
                    code='
          <template>
            <Switch v-model="toggle" :inverted="true" label="Nechci dostávat e-maily" />
          </template>
        '
                >
                    <Switch v-model="state.toggle" :inverted="true" label="Nechci dostávat e-maily" />
                </Preview>
            </Example>

            <Example title="Povinné pole">
                <p>Pokud je prop <Prop>required</Prop> nastaven, zobrazí se u popisku hvězdička.</p>
                <Preview
                    code='
          <template>
            <Switch v-model="toggle" label="Souhlasím s podmínkami" required />
          </template>
        '
                >
                    <Switch v-model="state.toggle" label="Souhlasím s podmínkami" required />
                </Preview>
            </Example>

            <Example title="Podpora formu">
                <p>Switch automaticky propisuje <Prop>name</Prop> a podporuje validaci chyb pomocí <Prop>error</Prop>.</p>
                <Preview
                    code='
          <template>
            <Switch v-model="toggle" name="newsletter" error="Povinné pole" label="Chci odebírat novinky" />
          </template>
        '
                >
                    <Switch v-model="state.toggle" name="newsletter" error="Povinné pole" label="Chci odebírat novinky" />
                </Preview>
            </Example>

            <Example title="Help">
                <p>
                    Prop
                    <Prop>help</Prop>
                    umožňuje zobrazit nápovědu.
                </p>
                <Preview
                    code='
          <template>
            <Switch v-model="toggle" label="Zapnout funkci" help="Nápověda" />
          </template>
        '
                >
                    <Switch v-model="state.toggle" label="Zapnout funkci" help="Nápověda" />
                </Preview>
            </Example>
            <Example title="Vlastnosti">
                <div class="overflow-x-auto">
                    <table class="w-full text-sm text-left border border-border dark:border-dark-border">
                        <thead class="bg-muted dark:bg-dark-muted">
                            <tr>
                                <th class="px-4 py-2">Prop</th>
                                <th class="px-4 py-2">Typ</th>
                                <th class="px-4 py-2">Popis</th>
                            </tr>
                        </thead>
                        <tbody>
                            <tr>
                                <td class="px-4 py-2 font-mono"><Prop>modelValue</Prop></td>
                                <td class="px-4 py-2"><code>Boolean | String | Number</code></td>
                                <td class="px-4 py-2">Vstupní hodnota toggle komponenty (např. <code>true</code>, <code>'1'</code>).</td>
                            </tr>
                            <tr>
                                <td class="px-4 py-2 font-mono"><Prop>label</Prop></td>
                                <td class="px-4 py-2"><code>String</code></td>
                                <td class="px-4 py-2">Popisek vedle přepínače.</td>
                            </tr>
                            <tr>
                                <td class="px-4 py-2 font-mono"><Prop>id</Prop></td>
                                <td class="px-4 py-2"><code>String</code></td>
                                <td class="px-4 py-2">Volitelný ID inputu (HTML atribut).</td>
                            </tr>
                            <tr>
                                <td class="px-4 py-2 font-mono"><Prop>inverted</Prop></td>
                                <td class="px-4 py-2"><code>Boolean</code></td>
                                <td class="px-4 py-2">Převrátí logiku zapnuto/vypnuto (<code>true</code> znamená <code>false</code>).</td>
                            </tr>
                            <tr>
                                <td class="px-4 py-2 font-mono"><Prop>size</Prop></td>
                                <td class="px-4 py-2"><code>String</code></td>
                                <td class="px-4 py-2">Velikost přepínače (výchozí <code>default</code>).</td>
                            </tr>
                            <tr>
                                <td class="px-4 py-2 font-mono"><Prop>required</Prop></td>
                                <td class="px-4 py-2"><code>Boolean</code></td>
                                <td class="px-4 py-2">Zobrazí hvězdičku u popisku, pokud je pole povinné.</td>
                            </tr>
                            <tr>
                                <td class="px-4 py-2 font-mono"><Prop>name</Prop></td>
                                <td class="px-4 py-2"><code>String</code></td>
                                <td class="px-4 py-2">Název inputu.</td>
                            </tr>
                            <tr>
                                <td class="px-4 py-2 font-mono"><Prop>error</Prop></td>
                                <td class="px-4 py-2"><code>String</code></td>
                                <td class="px-4 py-2">Chybová hláška zobrazena pod komponentou.</td>
                            </tr>
                            <tr>
                                <td class="px-4 py-2 font-mono">
                                    <Prop>help</Prop>
                                </td>
                                <td class="px-4 py-2"><code>String</code></td>
                                <td class="px-4 py-2">Zobrazí nápovědu v tooltipu.</td>
                            </tr>
                        </tbody>
                    </table>
                </div>
            </Example>

            <Example title="Události">
                <div class="overflow-x-auto">
                    <table class="w-full text-sm text-left border border-border dark:border-dark-border">
                        <thead class="bg-muted dark:bg-dark-muted">
                            <tr>
                                <th class="px-4 py-2 whitespace-nowrap">Událost</th>
                                <th class="px-4 py-2 whitespace-nowrap">Popis</th>
                            </tr>
                        </thead>
                        <tbody>
                            <tr>
                                <td class="px-4 py-2 font-mono"><code>@update:modelValue</code></td>
                                <td class="px-4 py-2">Vyvoláno při změně hodnoty toggle přepínače.</td>
                            </tr>
                            <tr>
                                <td class="px-4 py-2 font-mono"><code>@change</code></td>
                                <td class="px-4 py-2">Vyvoláno při změně (stejné jako update, ale samostatně emitováno).</td>
                            </tr>
                        </tbody>
                    </table>
                </div>
            </Example>
        </template>
    </DocPage>
</template>
